        elif char in pairs.keys():
            if not stack or stack.pop() != pairs[char]:
                return False

    return not stack

print(valid_parentheses('([{}])'))  # True
print(valid_parentheses('([)]'))  # False
print(valid_parentheses('{[]}'))  # True
print(valid_parentheses('({[]})'))  # True
print(valid_parentheses('({[})'))  # False

def deep_merge(d1: dict, d2: dict) -> dict:
    """
    Deeply merges two dictionaries. Values from d2 override d1. If both values are dicts, merge recursively.

    Args:
        d1 (dict): The first dictionary to merge.
        d2 (dict): The second dictionary to merge.

    Returns:
        dict: The merged dictionary.
    """
    merged = {}
    for key in set(d1.keys()) | set(d2.keys()):
        value = d1.get(key, d2.get(key, None))
        if isinstance(value, dict) and isinstance(d2.get(key, None), dict):
            merged[key] = deep_merge(value, d2.get(key, None))
        else:
            merged[key] = value
    return merged

d1 = {'a': 1, 'b': {'c': 2}}
d2 = {'b': {'d': 3}, 'e': 4}
merged = deep_merge(d1, d2)
print(merged)  # {'a': 1, 'b': {'c': 2, 'd': 3}, 'e': 4}

def is_prime(n: int) -> bool:
    """Check if a number is prime."""
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

def nth_prime(n: int) -> int:
    """Return the nth prime number (1-indexed)."""
    primes = []
    num = 2
    while len(primes) < n:
        if is_prime(num):
            primes.append(num)
        num += 1
    return primes[-1]

print(nth_prime(1))  # 2
print(nth_prime(2))  # 3
print(nth_prime(10))  # 29
